import { createContext, useContext, useState, useEffect } from 'react';
import axios from 'axios';

const Ctx = createContext();
export const useAuth = () => useContext(Ctx);

export const API = axios.create({ baseURL: '/api' });

// Attach token to every request automatically
API.interceptors.request.use(cfg => {
  const t = localStorage.getItem('pf_token');
  if (t) cfg.headers.Authorization = `Bearer ${t}`;
  return cfg;
});

export function AuthProvider({ children }) {
  const [user,       setUser]       = useState(null);
  const [loading,    setLoading]    = useState(true);
  const [registered, setRegistered] = useState(null); // null = checking

  useEffect(() => {
    // 1. Check if owner has registered yet
    API.get('/auth/status')
      .then(r => setRegistered(r.data.registered))
      .catch(() => setRegistered(false));

    // 2. Check if there's a saved token
    const token = localStorage.getItem('pf_token');
    if (token) {
      API.get('/auth/me')
        .then(r => setUser(r.data.user))
        .catch(() => localStorage.removeItem('pf_token'))
        .finally(() => setLoading(false));
    } else {
      setLoading(false);
    }
  }, []);

  const register = async (name, email, password) => {
    const r = await API.post('/auth/register', { name, email, password });
    localStorage.setItem('pf_token', r.data.token);
    setUser(r.data.user);
    setRegistered(true);
  };

  const login = async (email, password) => {
    const r = await API.post('/auth/login', { email, password });
    localStorage.setItem('pf_token', r.data.token);
    setUser(r.data.user);
  };

  const logout = () => {
    localStorage.removeItem('pf_token');
    setUser(null);
  };

  const updateUser = (u) => setUser(u);

  return (
    <Ctx.Provider value={{ user, loading, registered, register, login, logout, updateUser, API }}>
      {children}
    </Ctx.Provider>
  );
}
